 1→import { S3Client, PutObjectCommand, GetObjectCommand } from '@aws-sdk/client-s3';
 2→
 3→let client;
 4→
 5→function getClient() {
 6→  if (!client) {
 7→    client = new S3Client({
 8→      endpoint: process.env.S3_ENDPOINT,
 9→      region: process.env.S3_REGION ?? 'auto',
10→      credentials: {
11→        accessKeyId: process.env.S3_ACCESS_KEY,
12→        secretAccessKey: process.env.S3_SECRET_KEY,
13→      },
14→      forcePathStyle: true,
15→    });
16→  }
17→  return client;
18→}
19→
20→const bucket = () => process.env.S3_BUCKET;
21→const key = (id) => `skills/${id}.md`;
22→
23→export async function putSkill(id, content) {
24→  await getClient().send(new PutObjectCommand({
25→    Bucket: bucket(),
26→    Key: key(id),
27→    Body: content,
28→    ContentType: 'text/markdown',
29→  }));
30→}
31→
32→export async function getSkill(id) {
33→  try {
34→    const response = await getClient().send(new GetObjectCommand({
35→      Bucket: bucket(),
36→      Key: key(id),
37→    }));
38→    return await response.Body.transformToString();
39→  } catch (err) {
40→    if (err.name === 'NoSuchKey' || err.$metadata?.httpStatusCode === 404) {
41→      return null;
42→    }
43→    throw err;
44→  }
45→}
46→
47→export async function createPlaceholder(id, metadata) {
48→  const frontmatter = [
49→    '---',
50→    `status: "generating"`,
51→    `stage: "research"`,
52→    `contractAddress: "${metadata.contractAddress}"`,
53→    `chainId: 8453`,
54→    '---',
55→    '',
56→    '# Skill generation in progress',
57→    '',
58→  ].join('\n');
59→  await putSkill(id, frontmatter);
60→}
61→
62→export async function updateStage(id, stage) {
63→  const content = await getSkill(id);
64→  if (!content) throw new Error(`Skill ${id} not found`);
65→  const updated = content.replace(/^stage: ".+"$/m, `stage: "${stage}"`);
66→  await putSkill(id, updated);
67→}
68→
69→export async function markFailed(id, error) {
70→  const content = await getSkill(id);
71→  const base = content
72→    ? content.replace(/^status: ".+"$/m, 'status: "failed"')
73→    : `---\nstatus: "failed"\n---\n`;
74→  const withError = base.trimEnd() + `\n\n## Error\n\n${error}\n`;
75→  await putSkill(id, withError);
76→}
